import React, { useState } from 'react';
import { Card, CardHeader, CardTitle } from '../common/Card';
import { Button } from '../common/Button';
import { Modal } from '../common/Modal';
import {
  useProjectMemory,
  useUpdateProjectMemory,
  useDeleteProjectMemory,
  useAgentSessions,
} from '../../hooks/useMemory';
import { Brain, Edit2, Trash2, Plus, Clock, Save } from 'lucide-react';
import { clsx } from 'clsx';
import { MEMORY_KEYS, type MemoryKey, type Memory } from '../../types';

interface MemoryPanelProps {
  projectId: string;
  canManageMemory?: boolean;
}

const memoryLabels: Record<string, string> = {
  [MEMORY_KEYS.DECISIONS]: 'Decisions',
  [MEMORY_KEYS.CONTEXT]: 'Context',
  [MEMORY_KEYS.LEARNINGS]: 'Learnings',
  [MEMORY_KEYS.ARCHITECTURE]: 'Architecture',
};

const memoryDescriptions: Record<string, string> = {
  [MEMORY_KEYS.DECISIONS]: 'Key architectural and design decisions for this project',
  [MEMORY_KEYS.CONTEXT]: 'Technology stack, patterns, and conventions used',
  [MEMORY_KEYS.LEARNINGS]: 'What AI agents have learned about this project',
  [MEMORY_KEYS.ARCHITECTURE]: 'Key files, entry points, and project structure',
};

export function MemoryPanel({ projectId, canManageMemory = true }: MemoryPanelProps) {
  const { data: memories, isLoading } = useProjectMemory(projectId);
  const { data: sessions } = useAgentSessions(projectId, 5);
  const updateMemory = useUpdateProjectMemory();
  const deleteMemory = useDeleteProjectMemory();

  const [editingKey, setEditingKey] = useState<MemoryKey | null>(null);
  const [editContent, setEditContent] = useState('');
  const [showAddMemory, setShowAddMemory] = useState(false);
  const [newMemoryKey, setNewMemoryKey] = useState<MemoryKey | ''>('');
  const [newMemoryContent, setNewMemoryContent] = useState('');

  const memoryMap = new Map<string, Memory>();
  memories?.forEach(m => memoryMap.set(m.key, m));

  const handleEdit = (key: MemoryKey) => {
    const existing = memoryMap.get(key);
    setEditingKey(key);
    setEditContent(existing?.content || '');
  };

  const handleSave = async () => {
    if (!editingKey) return;

    try {
      await updateMemory.mutateAsync({
        projectId,
        key: editingKey,
        content: editContent,
      });
      setEditingKey(null);
      setEditContent('');
    } catch (error) {
      console.error('Failed to save memory:', error);
    }
  };

  const handleDelete = async (key: MemoryKey) => {
    if (!confirm('Are you sure you want to delete this memory?')) return;

    try {
      await deleteMemory.mutateAsync({ projectId, key });
    } catch (error) {
      console.error('Failed to delete memory:', error);
    }
  };

  const handleAddMemory = async () => {
    if (!newMemoryKey || !newMemoryContent.trim()) return;

    try {
      await updateMemory.mutateAsync({
        projectId,
        key: newMemoryKey,
        content: newMemoryContent,
      });
      setShowAddMemory(false);
      setNewMemoryKey('');
      setNewMemoryContent('');
    } catch (error) {
      console.error('Failed to add memory:', error);
    }
  };

  const availableKeys = Object.values(MEMORY_KEYS).filter(
    key => !memoryMap.has(key) && key in memoryLabels
  );

  if (isLoading) {
    return (
      <div className="flex items-center justify-center py-12">
        <div className="animate-spin w-8 h-8 border-2 border-brand-primary border-t-transparent rounded-full" />
      </div>
    );
  }

  return (
    <div className="space-y-6">
      {/* Memory Cards */}
      <Card>
        <CardHeader>
          <div className="flex items-center gap-2">
            <Brain className="w-5 h-5 text-brand-primary" />
            <CardTitle>Project Memory</CardTitle>
          </div>
          {canManageMemory && availableKeys.length > 0 && (
            <Button
              size="sm"
              variant="secondary"
              leftIcon={<Plus className="w-4 h-4" />}
              onClick={() => setShowAddMemory(true)}
            >
              Add
            </Button>
          )}
        </CardHeader>

        {memories && memories.length > 0 ? (
          <div className="space-y-4">
            {memories.map((memory) => (
              <div
                key={memory.id}
                className="p-4 bg-theme-bg rounded-lg border border-theme-border"
              >
                <div className="flex items-start justify-between mb-2">
                  <div>
                    <h4 className="font-medium text-theme-text">
                      {memoryLabels[memory.key] || memory.key}
                    </h4>
                    <p className="text-xs text-theme-muted">
                      Updated {new Date(memory.updatedAt).toLocaleDateString()}
                    </p>
                  </div>
                  {canManageMemory && (
                    <div className="flex items-center gap-1">
                      <button
                        onClick={() => handleEdit(memory.key as MemoryKey)}
                        className="p-1.5 text-theme-muted hover:text-theme-text transition-colors"
                      >
                        <Edit2 className="w-4 h-4" />
                      </button>
                      <button
                        onClick={() => handleDelete(memory.key as MemoryKey)}
                        className="p-1.5 text-theme-muted hover:text-brand-danger transition-colors"
                      >
                        <Trash2 className="w-4 h-4" />
                      </button>
                    </div>
                  )}
                </div>
                <p className="text-sm text-theme-muted whitespace-pre-wrap">
                  {memory.content}
                </p>
              </div>
            ))}
          </div>
        ) : (
          <div className="text-center py-8">
            <Brain className="w-10 h-10 mx-auto text-theme-muted mb-3" />
            <p className="text-theme-muted mb-4">
              No project memory saved yet
            </p>
            {canManageMemory && (
              <Button
                variant="secondary"
                size="sm"
                leftIcon={<Plus className="w-4 h-4" />}
                onClick={() => setShowAddMemory(true)}
              >
                Add Memory
              </Button>
            )}
          </div>
        )}
      </Card>

      {/* Recent Sessions */}
      {sessions && sessions.length > 0 && (
        <Card>
          <CardHeader>
            <div className="flex items-center gap-2">
              <Clock className="w-5 h-5 text-theme-muted" />
              <CardTitle>Recent Agent Sessions</CardTitle>
            </div>
          </CardHeader>
          <div className="space-y-3">
            {sessions.map((session) => (
              <div
                key={session.id}
                className="p-3 bg-theme-bg rounded-lg border border-theme-border"
              >
                <p className="text-sm text-theme-text">{session.summary}</p>
                <p className="text-xs text-theme-muted mt-1">
                  {new Date(session.createdAt).toLocaleString()}
                </p>
              </div>
            ))}
          </div>
        </Card>
      )}

      {/* Edit Memory Modal */}
      <Modal
        isOpen={!!editingKey}
        onClose={() => {
          setEditingKey(null);
          setEditContent('');
        }}
        title={`Edit ${editingKey ? memoryLabels[editingKey] || editingKey : ''}`}
        footer={
          <>
            <Button variant="secondary" onClick={() => setEditingKey(null)}>
              Cancel
            </Button>
            <Button
              onClick={handleSave}
              isLoading={updateMemory.isPending}
              leftIcon={<Save className="w-4 h-4" />}
            >
              Save
            </Button>
          </>
        }
      >
        <div>
          {editingKey && (
            <p className="text-sm text-theme-muted mb-3">
              {memoryDescriptions[editingKey]}
            </p>
          )}
          <textarea
            className="input resize-none"
            rows={8}
            value={editContent}
            onChange={(e) => setEditContent(e.target.value)}
            placeholder="Enter content..."
          />
        </div>
      </Modal>

      {/* Add Memory Modal */}
      <Modal
        isOpen={showAddMemory}
        onClose={() => {
          setShowAddMemory(false);
          setNewMemoryKey('');
          setNewMemoryContent('');
        }}
        title="Add Memory"
        footer={
          <>
            <Button variant="secondary" onClick={() => setShowAddMemory(false)}>
              Cancel
            </Button>
            <Button
              onClick={handleAddMemory}
              isLoading={updateMemory.isPending}
              disabled={!newMemoryKey || !newMemoryContent.trim()}
              leftIcon={<Plus className="w-4 h-4" />}
            >
              Add
            </Button>
          </>
        }
      >
        <div className="space-y-4">
          <div>
            <label className="block text-sm font-medium text-theme-text mb-1">
              Type
            </label>
            <select
              className="input"
              value={newMemoryKey}
              onChange={(e) => setNewMemoryKey(e.target.value as MemoryKey)}
            >
              <option value="">Select type...</option>
              {availableKeys.map(key => (
                <option key={key} value={key}>
                  {memoryLabels[key]}
                </option>
              ))}
            </select>
            {newMemoryKey && (
              <p className="text-xs text-theme-muted mt-1">
                {memoryDescriptions[newMemoryKey]}
              </p>
            )}
          </div>
          <div>
            <label className="block text-sm font-medium text-theme-text mb-1">
              Content
            </label>
            <textarea
              className="input resize-none"
              rows={6}
              value={newMemoryContent}
              onChange={(e) => setNewMemoryContent(e.target.value)}
              placeholder="Enter content..."
            />
          </div>
        </div>
      </Modal>
    </div>
  );
}

