import { v4 as uuidv4 } from 'uuid';
import {
  projectMemoryOps,
  globalMemoryOps,
  agentSessionOps,
  beadOps,
} from '../db/ops.js';

export interface Memory {
  id: string;
  projectId?: string;
  userId?: string;
  key: string;
  content: string;
  updatedAt: string;
}

export interface AgentSession {
  id: string;
  projectId: string;
  summary: string;
  contextUsed: Record<string, any>;
  createdAt: string;
}

export interface AgentContext {
  projectMemory: Record<string, string>;
  recentSessions: AgentSession[];
  currentTasks: any[];
  relatedContext?: Record<string, any>;
}

// Memory key types for consistent usage
export const MEMORY_KEYS = {
  DECISIONS: 'decisions',
  CONTEXT: 'context',
  LEARNINGS: 'learnings',
  ARCHITECTURE: 'architecture',
  PREFERENCES: 'preferences',
  PATTERNS: 'patterns',
} as const;

class MemoryService {
  /**
   * Get all memory for a project
   */
  async getProjectMemory(projectId: string, key?: string): Promise<Memory[]> {
    if (key) {
      const result = await projectMemoryOps.findByProjectIdAndKey(projectId, key) as any;
      return result ? [this.formatMemory(result)] : [];
    }

    const results = await projectMemoryOps.findByProjectId(projectId) as any[];
    return results.map(this.formatMemory);
  }

  /**
   * Update or create project memory
   */
  async updateProjectMemory(
    projectId: string,
    key: string,
    content: string,
    updatedBy?: string
  ): Promise<Memory> {
    const id = uuidv4();
    await projectMemoryOps.upsert(id, projectId, key, content, updatedBy || null, content, (updatedBy || null) as unknown as string);

    const result = await projectMemoryOps.findByProjectIdAndKey(projectId, key) as any;
    return this.formatMemory(result);
  }

  /**
   * Delete project memory
   */
  async deleteProjectMemory(projectId: string, key: string): Promise<void> {
    await projectMemoryOps.delete(projectId, key);
  }

  /**
   * Get all global memory for a user
   */
  async getGlobalMemory(userId: string, key?: string): Promise<Memory[]> {
    if (key) {
      const result = await globalMemoryOps.findByUserIdAndKey(userId, key) as any;
      return result ? [this.formatMemory(result)] : [];
    }

    const results = await globalMemoryOps.findByUserId(userId) as any[];
    return results.map(this.formatMemory);
  }

  /**
   * Update or create global memory
   */
  async updateGlobalMemory(
    userId: string,
    key: string,
    content: string
  ): Promise<Memory> {
    const id = uuidv4();
    await globalMemoryOps.upsert(id, userId, key, content, content);

    const result = await globalMemoryOps.findByUserIdAndKey(userId, key) as any;
    return this.formatMemory(result);
  }

  /**
   * Delete global memory
   */
  async deleteGlobalMemory(userId: string, key: string): Promise<void> {
    await globalMemoryOps.delete(userId, key);
  }

  /**
   * Build context for an agent session
   */
  async buildAgentContext(
    projectId: string,
    projectPath: string
  ): Promise<AgentContext> {
    // Get all project memory
    const projectMemoryList = await this.getProjectMemory(projectId);
    const projectMemory: Record<string, string> = {};
    for (const mem of projectMemoryList) {
      projectMemory[mem.key] = mem.content;
    }

    // Get recent sessions (last 3)
    const recentSessions = await this.getRecentSessions(projectId, 3);

    // Get current tasks from beads
    const allBeads = await beadOps.findByProjectId(projectId) as any[];
    const currentTasks = allBeads
      .filter(t => t.status !== 'completed')
      .map(t => ({
        id: t.id,
        subject: t.subject,
        description: t.description,
        status: t.status,
        owner: t.owner,
      }));

    return {
      projectMemory,
      recentSessions,
      currentTasks,
    };
  }

  /**
   * Save agent session summary
   */
  async saveSessionSummary(
    projectId: string,
    summary: string,
    contextUsed?: Record<string, any>
  ): Promise<AgentSession> {
    const id = uuidv4();
    const contextJson = contextUsed ? JSON.stringify(contextUsed) : null;

    await agentSessionOps.create(id, projectId, summary, contextJson);

    const result = await agentSessionOps.findById(id) as any;
    return this.formatSession(result);
  }

  /**
   * Get recent sessions for a project
   */
  async getRecentSessions(
    projectId: string,
    limit: number = 10
  ): Promise<AgentSession[]> {
    const results = await agentSessionOps.findRecentByProjectId(projectId, limit) as any[];
    return results.map(this.formatSession);
  }

  /**
   * Get all sessions for a project
   */
  async getAllSessions(projectId: string): Promise<AgentSession[]> {
    const results = await agentSessionOps.findByProjectId(projectId) as any[];
    return results.map(this.formatSession);
  }

  /**
   * Format raw memory record
   */
  private formatMemory(record: any): Memory {
    return {
      id: record.id,
      projectId: record.projectId,
      userId: record.userId,
      key: record.key,
      content: record.content,
      updatedAt: record.updatedAt,
    };
  }

  /**
   * Format raw session record
   */
  private formatSession(record: any): AgentSession {
    let contextUsed = {};
    try {
      if (record.contextUsed) {
        contextUsed = JSON.parse(record.contextUsed);
      }
    } catch {
      // Invalid JSON
    }

    return {
      id: record.id,
      projectId: record.projectId,
      summary: record.summary,
      contextUsed,
      createdAt: record.createdAt,
    };
  }
}

export const memoryService = new MemoryService();

