import { useQuery, useMutation, useQueryClient } from '@tanstack/react-query';
import { api } from '../services/api';
import type { Memory, AgentSession, AgentContext, MemoryKey } from '../types';

// Project Memory hooks

export function useProjectMemory(projectId: string, key?: MemoryKey) {
  return useQuery({
    queryKey: ['projectMemory', projectId, key],
    queryFn: async () => {
      const url = key
        ? `/memory/project/${projectId}?key=${key}`
        : `/memory/project/${projectId}`;
      const response = await api.get<Memory[]>(url);
      if (!response.success) {
        throw new Error(response.error);
      }
      return response.data!;
    },
    enabled: !!projectId,
  });
}

export function useUpdateProjectMemory() {
  const queryClient = useQueryClient();

  return useMutation({
    mutationFn: async ({
      projectId,
      key,
      content,
    }: {
      projectId: string;
      key: MemoryKey;
      content: string;
    }) => {
      const response = await api.put<Memory>(`/memory/project/${projectId}/${key}`, {
        content,
      });
      if (!response.success) {
        throw new Error(response.error);
      }
      return response.data!;
    },
    onSuccess: (_, variables) => {
      queryClient.invalidateQueries({ queryKey: ['projectMemory', variables.projectId] });
      queryClient.invalidateQueries({ queryKey: ['agentContext', variables.projectId] });
    },
  });
}

export function useDeleteProjectMemory() {
  const queryClient = useQueryClient();

  return useMutation({
    mutationFn: async ({
      projectId,
      key,
    }: {
      projectId: string;
      key: MemoryKey;
    }) => {
      const response = await api.delete(`/memory/project/${projectId}/${key}`);
      if (!response.success) {
        throw new Error(response.error);
      }
    },
    onSuccess: (_, variables) => {
      queryClient.invalidateQueries({ queryKey: ['projectMemory', variables.projectId] });
    },
  });
}

// Global Memory hooks

export function useGlobalMemory(key?: MemoryKey) {
  return useQuery({
    queryKey: ['globalMemory', key],
    queryFn: async () => {
      const url = key ? `/memory/global?key=${key}` : '/memory/global';
      const response = await api.get<Memory[]>(url);
      if (!response.success) {
        throw new Error(response.error);
      }
      return response.data!;
    },
  });
}

export function useUpdateGlobalMemory() {
  const queryClient = useQueryClient();

  return useMutation({
    mutationFn: async ({
      key,
      content,
    }: {
      key: MemoryKey;
      content: string;
    }) => {
      const response = await api.put<Memory>(`/memory/global/${key}`, {
        content,
      });
      if (!response.success) {
        throw new Error(response.error);
      }
      return response.data!;
    },
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ['globalMemory'] });
    },
  });
}

export function useDeleteGlobalMemory() {
  const queryClient = useQueryClient();

  return useMutation({
    mutationFn: async ({ key }: { key: MemoryKey }) => {
      const response = await api.delete(`/memory/global/${key}`);
      if (!response.success) {
        throw new Error(response.error);
      }
    },
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ['globalMemory'] });
    },
  });
}

// Agent Context hooks

export function useAgentContext(projectId: string) {
  return useQuery({
    queryKey: ['agentContext', projectId],
    queryFn: async () => {
      const response = await api.get<AgentContext>(`/memory/context/${projectId}`);
      if (!response.success) {
        throw new Error(response.error);
      }
      return response.data!;
    },
    enabled: !!projectId,
  });
}

// Session hooks

export function useAgentSessions(projectId: string, limit?: number) {
  return useQuery({
    queryKey: ['agentSessions', projectId, limit],
    queryFn: async () => {
      const url = limit
        ? `/memory/sessions/${projectId}?limit=${limit}`
        : `/memory/sessions/${projectId}`;
      const response = await api.get<AgentSession[]>(url);
      if (!response.success) {
        throw new Error(response.error);
      }
      return response.data!;
    },
    enabled: !!projectId,
  });
}

export function useSaveSessionSummary() {
  const queryClient = useQueryClient();

  return useMutation({
    mutationFn: async ({
      projectId,
      summary,
      contextUsed,
    }: {
      projectId: string;
      summary: string;
      contextUsed?: Record<string, any>;
    }) => {
      const response = await api.post<AgentSession>(`/memory/sessions/${projectId}`, {
        summary,
        contextUsed,
      });
      if (!response.success) {
        throw new Error(response.error);
      }
      return response.data!;
    },
    onSuccess: (_, variables) => {
      queryClient.invalidateQueries({ queryKey: ['agentSessions', variables.projectId] });
      queryClient.invalidateQueries({ queryKey: ['agentContext', variables.projectId] });
    },
  });
}

