118	/**
119	 * Build retry context from a previous failed job.
120	 * Prefers structured data from job result/failureArtifacts; falls back to log scraping for old jobs.
121	 */
122	async function buildRetryContext(retryOfJobId: string): Promise<string | undefined> {
123	  const prevJob = await agentJobOps.findById(retryOfJobId) as any;
124	  if (!prevJob) return undefined;
125	
126	  const error: string = prevJob.error || 'Unknown failure';
127	  const log: string = prevJob.outputLog || '';
128	  const result = prevJob.result ? JSON.parse(prevJob.result) : null;
129	  const artifacts = result?.failureArtifacts;
130	
131	  // --- Extract structured data (prefer result, fall back to log scraping) ---
132	
133	  // Files written
134	  let filesWritten: string[] = result?.filesWritten || [];
135	  if (filesWritten.length === 0) {
136	    // Legacy fallback: scrape write_file tool calls from log
137	    const writePattern = /\[tool_use\].*?write_file.*?"path":\s*"([^"]+)"/g;
138	    let match;
139	    while ((match = writePattern.exec(log)) !== null) {
140	      filesWritten.push(match[1]);
141	    }
142	  }
143	
144	  // Files read (only available from structured data)
145	  const filesRead: string[] = result?.filesRead || [];
146	
147	  // Changed files from postflight diff (more accurate than write_file tracking)
148	  const changedFiles: string[] = artifacts?.changedFiles || [];
149	
150	  // Rescue branch
151	  const rescueBranch: string | undefined = artifacts?.rescueBranch || result?.rescueBranch;
152	
153	  // Branch pushed (success path or rescue)
154	  const branchPushed = !!rescueBranch || log.includes('Push verified') || log.includes('Push output');
155	
156	  // Failure analysis
157	  const failureAnalysis = artifacts?.failureAnalysis;
158	
159	  // Agent summary
160	  const agentSummary = result?.summary || '';
161	
162	  // Failure reason — use structured analysis, fall back to postflight log lines
163	  let failureReason = failureAnalysis
164	    ? `${failureAnalysis.title}: ${failureAnalysis.summary}`
165	    : error;
166	  if (!failureAnalysis) {
167	    const postflightLines = log.split('\n')
168	      .filter(line => line.includes('[postflight]'))
169	      .map(line => line.replace(/.*\[postflight\]\s*/, '').trim());
170	    for (const line of postflightLines) {
171	      if (line.includes('FAILED') || line.includes('failed') || line.includes('error')) {
172	        failureReason = line;
173	        break;
174	      }
175	    }
176	  }
177	
178	  // --- Compute retry depth ---
179	  const { depth: retryDepth, repeatedCategory } = await countRetryDepth(retryOfJobId);
180	  const attemptNumber = retryDepth + 1; // depth=0 means first retry (attempt #2), but retryOfJobId existing means at least 1 prior
181	
182	  // --- Build the context block ---
183	  const parts: string[] = [
184	    `## Previous Attempt (retry #${attemptNumber})`,
185	    `This is retry attempt #${attemptNumber}. The task was attempted before but failed. Here\'s what happened:`,
186	    '',
187	  ];
188	
189	  // Strong directive when same failure category keeps repeating
190	  if (retryDepth >= 2 && repeatedCategory) {
191	    parts.push(
192	      `IMPORTANT: This task has failed ${retryDepth} times with the same issue (${repeatedCategory}).`,
193	      'Do NOT repeat the previous approach. If the failure is related to test configuration,',
194	      'project setup, or build tools — IGNORE it entirely. Focus only on your assigned',
195	      'code change and call mark_complete. The system handles tests separately.',
196	      '',
197	    );
198	  }
199	
200	  if (agentSummary) {
201	    parts.push(`Progress: ${agentSummary}`);
202	  }
203	
204	  // Use changedFiles (postflight git status) if available, else filesWritten (tool tracking)
205	  const fileList = changedFiles.length > 0 ? changedFiles : filesWritten;
206	  if (fileList.length > 0) {
207	    parts.push(`Files modified: ${fileList.join(', ')}`);
208	  }
209	  if (filesRead.length > 0) {
210	    // Only show unique reads that aren't also writes (skip noise)
211	    const readOnly = filesRead.filter(f => !fileList.includes(f));
212	    if (readOnly.length > 0 && readOnly.length <= 15) {
213	      parts.push(`Files read: ${readOnly.join(', ')}`);
214	    }
215	  }
216	
217	  parts.push(`Failure: ${failureReason}`);
218	
219	  if (failureAnalysis?.suggestions?.length) {
220	    parts.push(`Suggestions: ${failureAnalysis.suggestions.join('; ')}`);
221	  }
222	
223	  if (rescueBranch) {
224	    parts.push(`Rescue branch: ${rescueBranch} — your previous uncommitted changes were saved here`);
225	  }
226	  parts.push(`Code preserved: ${branchPushed ? 'Yes' : 'No — changes were lost, redo them'}`);
227	
228	  // Include a truncated diff excerpt so the agent can see exactly what was done
229	  if (artifacts?.uncommittedDiff) {
230	    const diffExcerpt = artifacts.uncommittedDiff.length > 3000
231	      ? artifacts.uncommittedDiff.substring(0, 3000) + '\n... (diff truncated)'
232	      : artifacts.uncommittedDiff;
233	    parts.push('', '### Previous diff (uncommitted changes at time of failure)', '```diff', diffExcerpt, '```');
234	  }
235	
236	  parts.push('');
237	  if (rescueBranch) {
238	    parts.push(
239	      'The rescue branch has your previous changes. You are starting from a clean checkout of the default branch.',
240	      'Review what was done in the diff above, understand why it failed, and apply a corrected version.',
241	      'Do NOT cherry-pick or merge the rescue branch — it may contain the bug that caused the failure.',
242	    );
243	  } else if (branchPushed) {
244	    parts.push('The previous code changes are on the branch — review them and fix the issue that caused the failure.');
245	  } else {
246	    parts.push('Previous changes were lost. Redo the file changes (you know exactly what\'s needed from the diff above) and fix the issue that caused the failure.');
247	  }
248	
249	  return parts.join('\n');
250	}
