252	/**
253	 * Build the complete context for an agent job
254	 */
255	export async function buildAgentContext(
256	  jobId: string,
257	  projectId: string,
258	  prompt: string,
259	  beadId?: string,
260	  runtime?: ProjectRuntime,
261	  retryOf?: string
262	): Promise<AgentContext> {
263	  // Get project info
264	  const project = await projectOps.findById(projectId) as any;
265	  if (!project) {
266	    throw new Error(`Project ${projectId} not found`);
267	  }
268	
269	  const projectInfo: ProjectInfo = {
270	    id: project.id,
271	    name: project.name,
272	    description: project.description,
273	    githubRepo: project.githubRepo,
274	    aiProvider: project.aiProvider || 'claude',
275	    aiModel: project.aiModel || 'claude-sonnet-4-20250514',
276	    mergeStrategy: project.mergeStrategy || 'pr',
277	  };
278	
279	  // Get project memory
280	  const memoryEntries = await projectMemoryOps.findByProjectId(projectId) as any[];
281	  const memory: ProjectMemory = {};
282	  for (const entry of memoryEntries) {
283	    memory[entry.key] = entry.content;
284	  }
285	
286	  // Get credentials (only what agent needs)
287	  const credentials: AgentCredentials = {};
288	  const resolved = await resolveGitHubToken(project.userId, project.githubRepo);
289	  if (resolved) {
290	    credentials.github = resolved.token;
291	  }
292	
293	  // Build task details, enriching with bead info if available
294	  const task: TaskDetails = {
295	    beadId,
296	    prompt,
297	  };
298	
299	  if (beadId) {
300	    const bead = await beadOps.findById(beadId) as any;
301	    if (bead) {
302	      task.priority = bead.priority;
303	      // Build enriched prompt from bead fields + original prompt.
304	      // The prompt from the UI dispatch modal may already contain subject/description,
305	      // so structure clearly with headers to avoid confusing the agent.
306	      const sections: string[] = [`## Task: ${bead.subject}`];
307	      if (bead.description) {
308	        sections.push('', bead.description);
309	      }
310	      if (bead.preInstructions) {
311	        sections.push('', '## Implementation Instructions', bead.preInstructions);
312	      }
313	      // Only append the raw prompt if it adds info beyond what the bead provides
314	      const promptAddsInfo = prompt &&
315	        !prompt.startsWith(bead.subject) &&
316	        prompt !== `Complete the task: ${bead.subject}`;
317	      if (promptAddsInfo) {
318	        sections.push('', '## Additional Context', prompt);
319	      }
320	      task.prompt = sections.join('\n');
321	    }
322	  }
323	
324	  // Inject retry context if this is a retry of a previous job
325	  if (retryOf) {
326	    const retryContext = await buildRetryContext(retryOf);
327	    if (retryContext) {
328	      task.prompt = `${retryContext}\n\n---\n\n${task.prompt}`;
329	    }
330	  }
331	
332	  // Get agent instructions (project-specific or default with runtime templating)
333	  const instructionsEntry = await projectMemoryOps.findByProjectIdAndKey(
334	    projectId,
335	    'AGENT_INSTRUCTIONS'
336	  ) as any;
337	  const instructions = instructionsEntry?.content || buildDefaultInstructions(runtime);
338	
339	  // Get tool definitions — exclude GitHub tools when project has no repo
340	  const tools = getToolDefinitions({ hasGithub: !!projectInfo.githubRepo });
341	
342	  return {
343	    jobId,
344	    project: projectInfo,
345	    task,
346	    memory,
347	    instructions,
348	    credentials,
349	    tools,
350	    workDir: '/home/user/repo',
351	  };
352	}
353	
354	/**
355	 * Build the system prompt for Claude
356	 */
357	export function buildSystemPrompt(context: AgentContext): string {
358	  // Separate well-known keys from generic project notes
359	  const wellKnownKeys = new Set(['AGENT_INSTRUCTIONS', 'AGENT_RULES']);
360	  const agentRules = context.memory['AGENT_RULES'];
361	
362	  const memorySection = Object.entries(context.memory)
363	    .filter(([key]) => !wellKnownKeys.has(key))
364	    .map(([key, value]) => `### ${key}\n${value}`)
365	    .join('\n\n');
366	
367	  const sections = [
368	    context.instructions,
369	    '',
370	    `## Project: ${context.project.name}`,
371	    context.project.description ? `${context.project.description}` : '',
372	    context.project.githubRepo ? `Repository: ${context.project.githubRepo}` : '',
373	  ];
374	
375	  if (agentRules) {
376	    sections.push('', '## Project-Specific Rules', agentRules);
377	  }
378	
379	  if (context.repoStructure) {
380	    sections.push('', '## Project Structure', '```', context.repoStructure, '```');
381	  }
382	
383	  if (memorySection) {
384	    sections.push('', '## Project Notes', memorySection);
385	  }
386	
387	  sections.push('', `## Working Directory: ${context.workDir}`);
388	
389	  return sections.filter(s => s !== undefined).join('\n').trim();
390	}
391	
392	/**
393	 * Extract key memories from agent session for storage
394	 */
395	export function extractMemories(
396	  sessionOutput: string
397	): Array<{ key: string; content: string }> {
398	  const memories: Array<{ key: string; content: string }> = [];
399	
400	  // Look for decision logs in the output
401	  const decisionPattern = /\[DECISION:(\w+)\]\s*(.+)/g;
402	  let match;
403	  while ((match = decisionPattern.exec(sessionOutput)) !== null) {
404	    memories.push({
405	      key: match[1],
406	      content: match[2].trim(),
407	    });
408	  }
409	
410	  return memories;
411	}
