/**
 * Agent Context Builder
 * Compiles all necessary context for an agent to execute a task
 */

import { projectOps, projectMemoryOps, beadOps, agentJobOps } from '../db/ops.js';
import { resolveGitHubToken } from './github-app.js';
import { getToolDefinitions } from './agent-tools/index.js';
import { countRetryDepth } from './failure-analysis.js';
import type { ProjectRuntime } from './project-runtime.js';

export interface ProjectInfo {
  id: string;
  name: string;
  description?: string;
  githubRepo?: string;
  aiProvider: string;
  aiModel: string;
  mergeStrategy: 'pr' | 'direct';
}

export interface TaskDetails {
  beadId?: string;
  prompt: string;
  priority?: number;
}

export interface ProjectMemory {
  [key: string]: string;
}

export interface AgentCredentials {
  github?: string;
  // Add other service credentials as needed
}

export interface AgentContext {
  jobId: string;
  project: ProjectInfo;
  task: TaskDetails;
  memory: ProjectMemory;
  instructions: string;
  credentials: AgentCredentials;
  tools: Array<{ name: string; description: string; input_schema: any }>;
  workDir: string;
  repoStructure?: string;
  runtimeHint?: string;
}

/**
 * Build default agent instructions, templated with runtime details.
 */
function buildDefaultInstructions(runtime?: ProjectRuntime): string {
  const installNote = runtime?.installCommand
    ? `- Dependencies are installed (\`${runtime.installCommand.replace(/ 2>&1$/, '')}\` has been run)`
    : '- Dependencies are installed (if applicable)';

  const doNotInstall = runtime?.installCommand
    ? `- Do NOT install dependencies — they are already installed`
    : '- Do NOT install dependencies — the system handles this';

  const doNotTest = runtime?.testCommand
    ? `- Do NOT run tests — the system runs \`${runtime.testCommand.replace(/ 2>&1$/, '')}\` after you finish`
    : '- Do NOT try to run tests — the system runs tests after you finish';

  const runtimeNote = runtime && runtime.language !== 'unknown'
    ? `\n\n## Runtime\nThis is a ${runtime.displayName} project.`
    : '';

  return `You are a focused code-change agent. Your ONLY job is to modify files to complete the assigned task.

## What Has Already Been Done For You
- The repository is cloned to your working directory
- A feature branch has been created and checked out
${installNote}
- Git credentials are configured

## What You Should Do
1. **Diagnose first**: Understand the root cause before changing code. For layout/visual issues, analyze the overall structure (grid, flexbox containers, parent elements) — don't just add properties to individual elements. For bugs, trace the actual code path.
2. Read only the files relevant to your task — do NOT explore the entire codebase
3. Make the minimal changes needed to fix the root cause — not symptoms
4. Use read_file to verify your changes look correct
5. If you renamed or removed any export, use glob to verify no other file still imports the old name before calling mark_complete
6. Call mark_complete with a summary of what you changed and WHY it fixes the issue

## What You Should NOT Do
- Do NOT run git commands (commit, push, branch) — the system handles this after you finish
${doNotInstall}
- Do NOT run build, compile, or type-check commands — the system runs these after you finish
- Do NOT explore directories unrelated to your task
${doNotTest}
- Do NOT create or switch branches — you are already on the correct branch

## Your Available Tools
- read_file: Read a file's contents
- edit_file: Make a targeted search-and-replace edit (PREFERRED for modifying existing files)
- write_file: Create or overwrite a file (use only for new files or when edit_file can't work)
- list_files: List directory contents (use sparingly — check the project structure below first)
- glob: Find files matching a pattern
- delete_file: Remove a file
- run_command: Run a shell command (for reading config files or checking syntax — NOT for builds or tests)
- report_progress: Report what you're doing
- mark_complete: Signal that you're done (REQUIRED — always call this when finished)

## Important
- Your working directory is the repository root. Do NOT use \`cd\` — it does not persist between commands. Use absolute paths or paths relative to the repo root.
- Make focused, minimal changes — do not refactor unrelated code
- If the task is unclear, do your best interpretation and note assumptions in mark_complete
- If you discover you are blocked by a missing dependency or unclear requirement that prevents completion, call mark_blocked instead of wasting time on workarounds

## Communication Style
- Be concise. Do not narrate your thinking or announce plans before acting.
- Use report_progress for brief status updates (e.g., "Updating Header.tsx").
- Do NOT emit conversational filler ("Perfect!", "Great!", "Now I understand...").
- Do NOT list numbered plans of what you're about to do — just do it.${runtimeNote}`;
}

/**
 * Build retry context from a previous failed job.
 * Prefers structured data from job result/failureArtifacts; falls back to log scraping for old jobs.
 */
async function buildRetryContext(retryOfJobId: string): Promise<string | undefined> {
  const prevJob = await agentJobOps.findById(retryOfJobId) as any;
  if (!prevJob) return undefined;

  const error: string = prevJob.error || 'Unknown failure';
  const log: string = prevJob.outputLog || '';
  const result = prevJob.result ? JSON.parse(prevJob.result) : null;
  const artifacts = result?.failureArtifacts;

  // --- Extract structured data (prefer result, fall back to log scraping) ---

  // Files written
  let filesWritten: string[] = result?.filesWritten || [];
  if (filesWritten.length === 0) {
    // Legacy fallback: scrape write_file tool calls from log
    const writePattern = /\[tool_use\].*?write_file.*?"path":\s*"([^"]+)"/g;
    let match;
    while ((match = writePattern.exec(log)) !== null) {
      filesWritten.push(match[1]);
    }
  }

  // Files read (only available from structured data)
  const filesRead: string[] = result?.filesRead || [];

  // Changed files from postflight diff (more accurate than write_file tracking)
  const changedFiles: string[] = artifacts?.changedFiles || [];

  // Rescue branch
  const rescueBranch: string | undefined = artifacts?.rescueBranch || result?.rescueBranch;

  // Branch pushed (success path or rescue)
  const branchPushed = !!rescueBranch || log.includes('Push verified') || log.includes('Push output');

  // Failure analysis
  const failureAnalysis = artifacts?.failureAnalysis;

  // Agent summary
  const agentSummary = result?.summary || '';

  // Failure reason — use structured analysis, fall back to postflight log lines
  let failureReason = failureAnalysis
    ? `${failureAnalysis.title}: ${failureAnalysis.summary}`
    : error;
  if (!failureAnalysis) {
    const postflightLines = log.split('\n')
      .filter(line => line.includes('[postflight]'))
      .map(line => line.replace(/.*\[postflight\]\s*/, '').trim());
    for (const line of postflightLines) {
      if (line.includes('FAILED') || line.includes('failed') || line.includes('error')) {
        failureReason = line;
        break;
      }
    }
  }

  // --- Compute retry depth ---
  const { depth: retryDepth, repeatedCategory } = await countRetryDepth(retryOfJobId);
  const attemptNumber = retryDepth + 1; // depth=0 means first retry (attempt #2), but retryOfJobId existing means at least 1 prior

  // --- Build the context block ---
  const parts: string[] = [
    `## Previous Attempt (retry #${attemptNumber})`,
    `This is retry attempt #${attemptNumber}. The task was attempted before but failed. Here\'s what happened:`,
    '',
  ];

  // Strong directive when same failure category keeps repeating
  if (retryDepth >= 2 && repeatedCategory) {
    parts.push(
      `IMPORTANT: This task has failed ${retryDepth} times with the same issue (${repeatedCategory}).`,
      'Do NOT repeat the previous approach. If the failure is related to test configuration,',
      'project setup, or build tools — IGNORE it entirely. Focus only on your assigned',
      'code change and call mark_complete. The system handles tests separately.',
      '',
    );
  }

  if (agentSummary) {
    parts.push(`Progress: ${agentSummary}`);
  }

  // Use changedFiles (postflight git status) if available, else filesWritten (tool tracking)
  const fileList = changedFiles.length > 0 ? changedFiles : filesWritten;
  if (fileList.length > 0) {
    parts.push(`Files modified: ${fileList.join(', ')}`);
  }
  if (filesRead.length > 0) {
    // Only show unique reads that aren't also writes (skip noise)
    const readOnly = filesRead.filter(f => !fileList.includes(f));
    if (readOnly.length > 0 && readOnly.length <= 15) {
      parts.push(`Files read: ${readOnly.join(', ')}`);
    }
  }

  parts.push(`Failure: ${failureReason}`);

  if (failureAnalysis?.suggestions?.length) {
    parts.push(`Suggestions: ${failureAnalysis.suggestions.join('; ')}`);
  }

  if (rescueBranch) {
    parts.push(`Rescue branch: ${rescueBranch} — your previous uncommitted changes were saved here`);
  }
  parts.push(`Code preserved: ${branchPushed ? 'Yes' : 'No — changes were lost, redo them'}`);

  // Include a truncated diff excerpt so the agent can see exactly what was done
  if (artifacts?.uncommittedDiff) {
    const diffExcerpt = artifacts.uncommittedDiff.length > 3000
      ? artifacts.uncommittedDiff.substring(0, 3000) + '\n... (diff truncated)'
      : artifacts.uncommittedDiff;
    parts.push('', '### Previous diff (uncommitted changes at time of failure)', '```diff', diffExcerpt, '```');
  }

  parts.push('');
  if (rescueBranch) {
    parts.push(
      'The rescue branch has your previous changes. You are starting from a clean checkout of the default branch.',
      'Review what was done in the diff above, understand why it failed, and apply a corrected version.',
      'Do NOT cherry-pick or merge the rescue branch — it may contain the bug that caused the failure.',
    );
  } else if (branchPushed) {
    parts.push('The previous code changes are on the branch — review them and fix the issue that caused the failure.');
  } else {
    parts.push('Previous changes were lost. Redo the file changes (you know exactly what\'s needed from the diff above) and fix the issue that caused the failure.');
  }

  return parts.join('\n');
}

/**
 * Build the complete context for an agent job
 */
export async function buildAgentContext(
  jobId: string,
  projectId: string,
  prompt: string,
  beadId?: string,
  runtime?: ProjectRuntime,
  retryOf?: string
): Promise<AgentContext> {
  // Get project info
  const project = await projectOps.findById(projectId) as any;
  if (!project) {
    throw new Error(`Project ${projectId} not found`);
  }

  const projectInfo: ProjectInfo = {
    id: project.id,
    name: project.name,
    description: project.description,
    githubRepo: project.githubRepo,
    aiProvider: project.aiProvider || 'claude',
    aiModel: project.aiModel || 'claude-sonnet-4-20250514',
    mergeStrategy: project.mergeStrategy || 'pr',
  };

  // Get project memory
  const memoryEntries = await projectMemoryOps.findByProjectId(projectId) as any[];
  const memory: ProjectMemory = {};
  for (const entry of memoryEntries) {
    memory[entry.key] = entry.content;
  }

  // Get credentials (only what agent needs)
  const credentials: AgentCredentials = {};
  const resolved = await resolveGitHubToken(project.userId, project.githubRepo);
  if (resolved) {
    credentials.github = resolved.token;
  }

  // Build task details, enriching with bead info if available
  const task: TaskDetails = {
    beadId,
    prompt,
  };

  if (beadId) {
    const bead = await beadOps.findById(beadId) as any;
    if (bead) {
      task.priority = bead.priority;
      // Build enriched prompt from bead fields + original prompt.
      // The prompt from the UI dispatch modal may already contain subject/description,
      // so structure clearly with headers to avoid confusing the agent.
      const sections: string[] = [`## Task: ${bead.subject}`];
      if (bead.description) {
        sections.push('', bead.description);
      }
      if (bead.preInstructions) {
        sections.push('', '## Implementation Instructions', bead.preInstructions);
      }
      // Only append the raw prompt if it adds info beyond what the bead provides
      const promptAddsInfo = prompt &&
        !prompt.startsWith(bead.subject) &&
        prompt !== `Complete the task: ${bead.subject}`;
      if (promptAddsInfo) {
        sections.push('', '## Additional Context', prompt);
      }
      task.prompt = sections.join('\n');
    }
  }

  // Inject retry context if this is a retry of a previous job
  if (retryOf) {
    const retryContext = await buildRetryContext(retryOf);
    if (retryContext) {
      task.prompt = `${retryContext}\n\n---\n\n${task.prompt}`;
    }
  }

  // Get agent instructions (project-specific or default with runtime templating)
  const instructionsEntry = await projectMemoryOps.findByProjectIdAndKey(
    projectId,
    'AGENT_INSTRUCTIONS'
  ) as any;
  const instructions = instructionsEntry?.content || buildDefaultInstructions(runtime);

  // Get tool definitions — exclude GitHub tools when project has no repo
  const tools = getToolDefinitions({ hasGithub: !!projectInfo.githubRepo });

  return {
    jobId,
    project: projectInfo,
    task,
    memory,
    instructions,
    credentials,
    tools,
    workDir: '/home/user/repo',
  };
}

/**
 * Build the system prompt for Claude
 */
export function buildSystemPrompt(context: AgentContext): string {
  // Separate well-known keys from generic project notes
  const wellKnownKeys = new Set(['AGENT_INSTRUCTIONS', 'AGENT_RULES']);
  const agentRules = context.memory['AGENT_RULES'];

  const memorySection = Object.entries(context.memory)
    .filter(([key]) => !wellKnownKeys.has(key))
    .map(([key, value]) => `### ${key}\n${value}`)
    .join('\n\n');

  const sections = [
    context.instructions,
    '',
    `## Project: ${context.project.name}`,
    context.project.description ? `${context.project.description}` : '',
    context.project.githubRepo ? `Repository: ${context.project.githubRepo}` : '',
  ];

  if (agentRules) {
    sections.push('', '## Project-Specific Rules', agentRules);
  }

  if (context.repoStructure) {
    sections.push('', '## Project Structure', '```', context.repoStructure, '```');
  }

  if (memorySection) {
    sections.push('', '## Project Notes', memorySection);
  }

  sections.push('', `## Working Directory: ${context.workDir}`);

  return sections.filter(s => s !== undefined).join('\n').trim();
}

/**
 * Extract key memories from agent session for storage
 */
export function extractMemories(
  sessionOutput: string
): Array<{ key: string; content: string }> {
  const memories: Array<{ key: string; content: string }> = [];

  // Look for decision logs in the output
  const decisionPattern = /\[DECISION:(\w+)\]\s*(.+)/g;
  let match;
  while ((match = decisionPattern.exec(sessionOutput)) !== null) {
    memories.push({
      key: match[1],
      content: match[2].trim(),
    });
  }

  return memories;
}

